import { Col, Row, Select } from "antd"
import { useEffect, useMemo, useState } from "react"
import TitleCustom from "src/components/TitleCustom"
import SpinCustom from "src/components/SpinCustom"
import ButtonCustom from "src/components/MyButton/Button"
import InputCustom from "src/components/Input/InputCustom"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import SelectCustom from "src/components/Select/SelectCustom"
import { getListComboByKey } from "src/lib/utils"
import { hideOnSinglePage, SYSTEM_KEY } from "src/constants/constants"
import { useSelector } from "react-redux"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import isBetween from "dayjs/plugin/isBetween"
import dayjs from "dayjs"
import moment from "moment"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import CB1 from "src/components/Modal/CB1"
import AdvertisementDetailModal from "../../components/AdvertisementDetailModal"
import { formatMoney } from "../../helpers/AdvertisementModalHelper"
import AdApproveService from "../../services"
import { contractStatus, paymentMethods } from "../../constant"
import notice from "src/components/Notice"
dayjs.extend(isBetween)

const AdvertisementApproval = () => {
  const [loading, setLoading] = useState(false)
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [pagination, setPagination] = useState({ pageSize: 20, currentPage: 1 })
  const [listData, setListData] = useState({
    Total: 0,
    ListContract: [],
  })
  const [detailModalOpen, setDetailModalOpen] = useState(false)
  const [selectedRequest, setSelectedRequest] = useState(null)
  const [filter, setFilter] = useState({
    MemberType: "all",
  })
  const [dateFilter, setDateFilter] = useState([])
  const [pendingRequestsCount, setPendingRequestsCount] = useState(0)

  const memberTypeOptions = useMemo(() => {
    const raw = getListComboByKey(SYSTEM_KEY.MEMBER_TYPE, listSystemKey) || []
    return [
      { CodeKey: "all", CodeValue: "all", Description: "Tất cả" },
      ...raw.map(item => ({
        ...item,
        CodeValue: Number(item.CodeValue),
      })),
    ]
  }, [listSystemKey])

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      key: "index",
      width: 70,
      align: "center",
      render: (value, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.pageSize * (pagination.currentPage - 1)}
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Mã hợp đồng</MainTableData>
          <SubTableData style={{ color: "white" }}>Ngày tạo</SubTableData>
        </div>
      ),
      dataIndex: "ContractCode",
      key: "CodeDate",
      align: "center",
      render: (value, record) => (
        <div>
          <MainTableData>{value || "-"}</MainTableData>
          <SubTableData>
            {moment(record.CreatedAt).format("DD/MM/YYYY")}
          </SubTableData>
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Giá trị hợp đồng</MainTableData>
          <SubTableData style={{ color: "white" }}>
            Phương thức thanh toán
          </SubTableData>
        </div>
      ),
      width: 200,
      dataIndex: "Amount",
      key: "MoneyBank",
      align: "center",
      render: (value, record) => (
        <div>
          <MainTableData>{formatMoney(value)}</MainTableData>
          <SubTableData>
            {paymentMethods.find(item => item.CodeKey === record.PaymentMethod)
              ?.CodeValue || "-"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: "Thời gian thực hiện",
      children: [
        {
          title: "Từ ngày",
          dataIndex: "StartDate",
          key: "StartDate",
          align: "center",
          render: text => text && moment(text).format("DD/MM/YYYY"),
        },
        {
          title: "Đến ngày",
          dataIndex: "EndDate",
          key: "EndDate",
          align: "center",
          render: text => text && moment(text).format("DD/MM/YYYY"),
        },
      ],
    },
    {
      title: "Phạm vi hiển thị",
      dataIndex: "PositionNames",
      key: "PositionNames",
      align: "center",
      render: value => value.join(", ") || "-",
    },
    {
      title: (
        <div>
          <MainTableData>Tên người tạo</MainTableData>
          <SubTableData style={{ color: "white" }}>Loại</SubTableData>
        </div>
      ),
      dataIndex: "RepresentativeName",
      key: "RepresentativeName",
      align: "center",
      render: (text, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData>{text || "-"}</MainTableData>
          <SubTableData className="fs-13">
            {memberTypeOptions.find(
              item => item.CodeValue === record.MemberType,
            )?.Description || "-"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Số điện thoại</MainTableData>
          <SubTableData style={{ color: "white" }}>Email</SubTableData>
        </div>
      ),
      key: "PhoneEmail",
      align: "center",
      render: (value, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record?.PhoneNumber || "-"}
          </MainTableData>
          <SubTableData className="fs-13">{record?.Email || "-"}</SubTableData>
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Người giới thiệu</MainTableData>
          <SubTableData style={{ color: "white" }}>Số điện thoại</SubTableData>
        </div>
      ),
      key: "Introducer",
      align: "center",
      render: record => (
        <div>
          <MainTableData className="max-line1">
            {record?.Referrer?.FullName || "-"}
          </MainTableData>
          <SubTableData className="fs-13">
            {record?.Referrer?.PhoneNumber || "-"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: "StatusAction",
      align: "center",
      render: (value, record) => {
        let statusStyle = {}

        if (value === 1) {
          statusStyle = { color: "#FF8C00", fontWeight: "bold" }
        } else if (value === 2) {
          statusStyle = { color: "#c20000", fontWeight: "bold" }
        } else if (value === 3) {
          statusStyle = { color: "#29bc00", fontWeight: "bold" }
        } else if (value === 4) {
          statusStyle = { color: "#4e4e4e", fontWeight: "bold" }
        }
        return (
          <div className="text-center">
            <div className="max-line2" style={statusStyle}>
              {contractStatus.find(item => item.CodeValue === value)
                ?.Description || "-"}
            </div>

            {record.Status === 1 && (
              <FloatActionWrapper
                size="small"
                className="float-action__wrapper"
              >
                <ButtonCircle
                  className="button-circle"
                  title="Chấp nhận"
                  iconName="check-circle"
                  style={{
                    background: "#EDF6FC",
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    CB1({
                      title: "Bạn có chắc chắn muốn duyệt không?",
                      icon: "check-circle",
                      okText: "Đồng ý",
                      // onOk: async close => {
                      //   const success = await approveRequests([record.UserID])
                      //   if (success) {
                      //     await fetchList()
                      //   }
                      //   close()
                      // },
                    })
                  }}
                />
                <ButtonCircle
                  className="button-circle"
                  title="Từ chối"
                  iconName="cancel"
                  style={{
                    background: "#FFE9EC",
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    CB1({
                      title: "Bạn có chắc chắn muốn từ chối không?",
                      icon: "cancel",
                      okText: "Đồng ý",
                      // onOk: async close => {
                      //   const success = await rejectRequests([record.UserID])
                      //   if (success) {
                      //     await fetchList()
                      //   }
                      //   close()
                      // },
                    })
                  }}
                />
              </FloatActionWrapper>
            )}
          </div>
        )
      },
    },
  ]

  // const requestStatusOptions = useMemo(() => {
  //   const list = getListComboByKey(SYSTEM_KEY.USER_STATUS, listSystemKey)
  //   return list || []
  // }, [listSystemKey])

  const onChangeFilter = (key, value) => {
    if (key === "Time" && value?.length !== 2) {
      setFilter(prev => ({
        ...prev,
        TimeFrom: null,
        TimeTo: null,
      }))
    } else if (key === "Time" && value?.length === 2) {
      setFilter(prev => ({
        ...prev,
        TimeFrom: value[0] ? dayjs(value[0]).toISOString() : null,
        TimeTo: value[1] ? dayjs(value[1]).add(1, "day").toISOString() : null,
      }))
    } else {
      setFilter(prev => ({
        ...prev,
        [key]: value,
      }))
    }
    setPagination(prev => ({ ...prev, currentPage: 1 }))
  }

  const handleViewDetail = record => {
    setSelectedRequest(record)
    setDetailModalOpen(true)
  }

  const countPendingRequest = () => {
    setPendingRequestsCount(
      listData.ListContract.filter(item => item.Status === 1).length,
    )
  }

  const getData = async () => {
    console.log("filter:", filter)

    try {
      setLoading(true)
      const response = await AdApproveService.GetListAdContracts(filter)

      setListData({
        Total: response?.Object.length || 0,
        ListContract: response?.Object || [],
      })

      countPendingRequest()
    } catch (error) {
      notice({ msg: "Có lỗi xảy ra khi lấy dữ liệu!" })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getData()
  }, [filter])

  return (
    <SpinCustom spinning={loading}>
      <Row
        className="box-action sticky"
        gutter={12}
        style={{ marginBottom: 16 }}
      >
        <Col span={24}>
          <TitleCustom className={"d-flex-sb"}>
            <div
              style={{
                position: "relative",
                display: "flex",
              }}
            >
              <span>
                Danh sách duyệt hợp đồng quảng cáo ({pendingRequestsCount})
              </span>
            </div>

            <div className="d-flex-end">
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow mr-8"
                // onClick={handleBulkApprove}
              >
                Chấp nhận
              </ButtonCustom>
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow"
                // onClick={handleBulkReject}
              >
                Từ chối
              </ButtonCustom>
            </div>
          </TitleCustom>
        </Col>
        <Col span={6}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo CCCD"
            onPressEnter={e => onChangeFilter("Identification", e.target.value)}
          />
        </Col>

        <Col span={6}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo Mã số thuế"
            onPressEnter={e => onChangeFilter("TaxCode", e.target.value)}
          />
        </Col>

        <Col span={6}>
          <DatePickerCustom
            type={"ranger"}
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            allowClear
            value={dateFilter}
            onChange={val => {
              onChangeFilter("Time", val), setDateFilter(val)
            }}
            placeholder={["Từ ngày", "Đến ngày"]}
          />
        </Col>
        <Col span={3}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            onChange={value => onChangeFilter("MemberType", value)}
            value={filter.MemberType}
            maxTagCount="responsive"
            label="Loại thành viên"
          >
            {memberTypeOptions.map((item, index) => (
              <Select.Option key={index} value={item.CodeValue}>
                {item.Description}
              </Select.Option>
            ))}
          </SelectCustom>
        </Col>
        <Col span={3}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            onChange={value => onChangeFilter("Status", value)}
            value={filter.Status}
            label="Trạng thái yêu cầu"
          >
            {contractStatus
              // ?.filter(item => item.CodeKey !== "USER_STATUS")
              ?.map((item, index) => (
                <SelectCustom.Option key={index} value={item.CodeValue}>
                  {item.Description}
                </SelectCustom.Option>
              ))}
          </SelectCustom>
        </Col>
      </Row>

      <TableCustom
        sticky={{ offsetHeader: -12 }}
        columns={columns}
        dataSource={listData.ListContract}
        textEmpty="Không có dữ liệu"
        rowKey="Code"
        pagination={{
          hideOnSinglePage: listData.Total <= hideOnSinglePage,
          current: pagination.currentPage,
          pageSize: pagination.pageSize,
          responsive: true,
          total: listData.Total,
          locale: { items_per_page: "" },
          showSizeChanger: listData.Total > 10,
          onChange: (currentPage, pageSize) => {
            setPagination(prev => ({
              ...prev,
              currentPage,
              pageSize,
            }))
          },
        }}
        onRow={record => ({
          onClick: () => {
            handleViewDetail(record)
          },
        })}
      />

      <AdvertisementDetailModal
        open={detailModalOpen}
        selectedRequest={selectedRequest}
        handleCancel={() => setDetailModalOpen(false)}
        handleOk={() => console.log("ok")}
        loading={loading}
      />
    </SpinCustom>
  )
}

export default AdvertisementApproval
