import { Button, Modal } from "antd"
import "../styles/DetailModal.scss"
import { getDataForModalDetail } from "../helpers/AdvertisementModalHelper"
import CB1 from "src/components/Modal/CB1"
import ContractModal from "./ContractModal"
import { useState } from "react"
import AdFilesCarosel from "./AdFilesCarosel"

const AdvertisementDetailModal = ({
  handleOk,
  handleCancel,
  loading,
  open,
  selectedRequest,
}) => {
  const [openContract, setOpenContract] = useState(false)
  const [typeModal, setTypeModal] = useState()

  const data = getDataForModalDetail(
    selectedRequest,
    setOpenContract,
    setTypeModal,
  )

  const footer = [
    <Button key="back" onClick={handleCancel}>
      Trở về
    </Button>,
  ]
  if (selectedRequest?.ButtonShow?.IsApprove) {
    footer.push(
      <Button
        onClick={e => {
          e.stopPropagation()
          CB1({
            title: "Bạn có chắc chắn muốn duyệt không?",
            icon: "check-circle",
            okText: "Đồng ý",
            onOk: async close => {
              const success = await handleOk()
              if (success) {
                // await fetchList()
              }
              close()
            },
          })
        }}
        key="submit"
        type="primary"
        loading={loading}
      >
        Duyệt
      </Button>,
    )
  }
  if (selectedRequest?.ButtonShow?.IsReject) {
    footer.push(
      <Button
        onClick={e => {
          e.stopPropagation()
          CB1({
            title: "Bạn có chắc chắn muốn từ chối không?",
            icon: "check-circle",
            okText: "Đồng ý",
            onOk: async close => {
              const success = await handleCancel()
              if (success) {
                // await fetchList()
              }
              close()
            },
          })
        }}
        key="submit"
        type="primary"
        loading={loading}
      >
        Từ chối
      </Button>,
    )
  }

  return (
    <Modal
      width={1300}
      open={open}
      title="Chi Tiết Quảng Cáo"
      onOk={handleOk}
      onCancel={handleCancel}
      footer={footer}
    >
      <div className="modal">
        <AdFilesCarosel />
        {data.map((item, index) => (
          <div key={index}>
            <span className="modal-subtitle">{item.title}</span>
            <div className="modal-item-container">
              {item.children.length > 0 &&
                item.children.map((child, index) => {
                  if (child.value || child.button) {
                    return (
                      <div className="modal-item" key={index}>
                        <span className="modal-label">{child.label}:</span>
                        {child.value && (
                          <span className="modal-value">{child.value}</span>
                        )}
                        {child.button && (
                          <span className="modal-button">{child.button}</span>
                        )}
                      </div>
                    )
                  }
                  return <span key={index}></span>
                })}
            </div>
          </div>
        ))}
      </div>

      <ContractModal
        open={openContract}
        onCancel={() => setOpenContract(false)}
        selectedRequest={selectedRequest}
        type={typeModal}
      />
    </Modal>
  )
}

export default AdvertisementDetailModal
