import { Modal, Spin } from "antd"
import { useState } from "react"

const ContractModal = ({ open, onCancel, selectedRequest, type }) => {
  const [loading, setLoading] = useState(true)
  return (
    <Modal open={open} onCancel={onCancel} footer={null} width={800}>
      {type === "contract" && (
        <>
          <h2>Contract</h2>
          <iframe
            src={"https://sherlock-holm.es/pdf/a4/1-sided/"}
            width={"100%"}
            height={"800px"}
            style={{ display: loading ? "none" : "block" }}
            onLoad={() => setLoading(false)}
          ></iframe>
        </>
      )}

      {loading && (
        <div style={{ textAlign: "center", margin: "20px 0" }}>
          <Spin />
        </div>
      )}
    </Modal>
  )
}

export default ContractModal
