import { Button } from "antd"
import moment from "moment"

export function getDataForModalDetail(
  selectedRequest,
  setOpenContract,
  setTypeModal,
) {
  const data = [
    {
      title: "Thông tin quảng cáo",
      children: [
        {
          label: "Mã hợp đồng",
          value: selectedRequest?.Code || "N/A",
        },
        {
          label: "Trạng thái",
          value: selectedRequest?.Status || "N/A",
        },
        {
          label: "Phạm vi hiển thị",
          value: selectedRequest?.DisplayPosition || "N/A",
        },
        {
          label: "Ngày tạo",
          value:
            moment(selectedRequest?.CreateDate).format("DD/MM/YYYY") || "N/A",
        },
        {
          label: "Từ ngày",
          value:
            moment(selectedRequest?.FromDate).format("DD/MM/YYYY") || "N/A",
        },
        {
          label: "Đến ngày",
          value: moment(selectedRequest?.ToDate).format("DD/MM/YYYY") || "N/A",
        },
        {
          label: "Hợp đồng",
          button: (
            <Button
              onClick={() => {
                setOpenContract(true), setTypeModal("contract")
              }}
              style={{ fontSize: "14px", color: "#01b29e" }}
            >
              Contract PDF
            </Button>
          ),
        },

      ],
    },
    {
      title: "Thanh toán",
      children: [
        {
          label: "Đơn giá",
          value: selectedRequest?.Money
            ? formatMoney(selectedRequest.Money)
            : "",
        },
        {
          label: "Phương thức",
          value: selectedRequest?.PaymentMethod || "N/A",
        },
        {
          label: "Ngày thanh toán",
          value:
            moment(selectedRequest?.PaymentDate).format("DD/MM/YYYY") || "N/A",
        },
        {
          label: "Trạng thái",
          value: selectedRequest?.PaymentStatus || "N/A",
        },
        {
          label: "Số tài khoản",
          value: selectedRequest?.BankAccount || null,
        },
        {
          label: "Ngân hàng",
          value: selectedRequest?.BankName || null,
        },
      ],
    },
    {
      title: "Thông tin người đặt quảng cáo",
      children: [
        {
          label: "Tên người tạo",
          value: selectedRequest?.MemberName || "N/A",
        },
        {
          label: "Số CCCD/MST",
          value: selectedRequest?.Identity || "N/A",
        },
        {
          label: "Loại",
          value: selectedRequest?.MemberType || "N/A",
        },

        {
          label: "Số điện thoại",
          value: selectedRequest?.PhoneNumber || "N/A",
        },
        {
          label: "Email",
          value: selectedRequest?.Email || "N/A",
        },
      ],
    },
    {
      title: "Thông tin người giới thiệu",
      children: [
        {
          label: "Người giới thiệu",
          value: selectedRequest?.IntroducerName || "N/A",
        },
        {
          label: "Số điện thoại",
          value: selectedRequest?.IntroducerPhone || "N/A",
        },
      ],
    },
  ]
  return data
}

export function formatMoney(number) {
  return number.toLocaleString("vi-VN", {
    style: "currency",
    currency: "VND",
  })
}
