import React from "react"
import { Carousel } from "antd"

const slideStyle = {
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  height: "300px", // fixed height for carousel
  background: "#364d79",
}

const fakeData = [
  {
    url: "https://tse1.explicit.bing.net/th/id/OIP.AXUMO328KG6qOhyYTz16pQHaE7?w=626&h=417&rs=1&pid=ImgDetMain&o=7&rm=3",
    type: "image",
  },
  {
    url: "https://akm-img-a-in.tosshub.com/indiatoday/images/story/202002/teddy-1444642_960_720_0.jpeg",
    type: "image",
  },
]

const AdFilesCarosel = () => (
  <Carousel
    style={{ marginRight: "20px", marginBottom: "20px", borderRadius: '8px' }}
    arrows
    infinite={false}
  >
    {fakeData.map((file, idx) => {
      if (file.type.startsWith("image")) {
        return (
          <div key={idx} style={slideStyle}>
            <img
              src={file.url}
              alt="Ad"
              style={{
                maxWidth: "100%",
                maxHeight: "100%",
                objectFit: "contain",
              }}
            />
          </div>
        )
      }
      if (file.type.startsWith("video")) {
        return (
          <div key={idx} style={slideStyle}>
            <video style={{ maxWidth: "100%", maxHeight: "100%" }} controls>
              <source src={file.url} type={file.type} />
            </video>
          </div>
        )
      }
      return (
        <div key={idx} style={slideStyle}>
          <a href={file.url} target="_blank" rel="noreferrer">
            Download {file.name}
          </a>
        </div>
      )
    })}
  </Carousel>
)

export default AdFilesCarosel
